public class ActionQueryParameters : PagedQueryParameters<ActionEntity>
{
    private Guid? parentId;
    private bool? rootsOnly;

    /// Filter to children of a specific parent
    public ActionQueryParameters WithParent(Guid parentId)
    {
        this.parentId = parentId;
        return this;
    }

    /// Filter to root actions only (no parent)
    public ActionQueryParameters WithRootsOnly()
    {
        rootsOnly = true;
        return this;
    }

    public override IQueryable<ActionEntity> ApplyFilters(IQueryable<ActionEntity> query)
    {
        query = base.ApplyFilters(query);

        if (parentId is not null)
            query = query.Where(a => a.ParentActionId == parentId);

        if (rootsOnly == true)
            query = query.Where(a => a.ParentActionId == null);

        return query;
    }

    public IQueryable<ActionEntity> IncludeRelations(IQueryable<ActionEntity> query)
    {
        return query
            .AsSplitQuery()
            .Include(a => a.ParentAction);
    }
}

