// In the guard evaluation chain
public async Task<GuardResult> EvaluateSubActionDependencies(
    ActionEntity action, ActionsDbContext db, CancellationToken ct)
{
    var openChildren = await db.Actions
        .Where(a => a.ParentActionId == action.Id)
        .Where(a => !a.IsDeleted)
        .Where(a => a.CurrentState.StateType != "Terminal")
        .CountAsync(ct);

    if (openChildren > 0)
        return GuardResult.Failed("SubActionDependencies",
            $"{openChildren} sub-action(s) are not in a terminal state");

    return GuardResult.Passed();
}

public class GetActionDescendantIdsQuery(
    IDbContextFactory<ActionsDbContext> dbFactory)
{
    public async Task<HashSet<Guid>> ExecuteAsync(
        Guid parentActionId, CancellationToken ct)
    {
        await using var db = await dbFactory.CreateDbContextAsync(ct);

        // Load only Id + ParentActionId (lightweight)
        var pairs = await db.Actions
            .AsNoTracking()
            .Where(a => !a.IsDeleted)
            .Select(a => new { a.Id, a.ParentActionId })
            .ToListAsync(ct);

        // Build parent → children lookup
        var childrenByParent = pairs
            .Where(p => p.ParentActionId is not null)
            .GroupBy(p => p.ParentActionId!.Value)
            .ToDictionary(g => g.Key, g => g.Select(p => p.Id).ToList());

        // Stack-based traversal (no recursion)
        var result = new HashSet<Guid>();
        var stack = new Stack<Guid>();
        stack.Push(parentActionId);

        while (stack.Count > 0)
        {
            var current = stack.Pop();
            if (current != parentActionId)
                result.Add(current);

            if (childrenByParent.TryGetValue(current, out var children))
                foreach (var child in children)
                    stack.Push(child);
        }

        return result;
    }
}

